-#define DISPATCH_CONTIGUOUS(TRANSPOSED)                                                                    \
-  [&]() -> std::tuple<torch::Tensor, torch::Tensor> {                                                      \
-    switch (dtype) {                                                                                       \
-      case torch::kFloat32:                                                                                \
